QUnit.module("$.bsCalendar — Global API",function(){QUnit.test("version is 2.3.4",function(assert){assert.strictEqual($.bsCalendar.version,"2.3.4")});QUnit.test("about has expected fields",function(assert){const a=$.bsCalendar.about;assert.strictEqual(a.version,"2.3.4");assert.strictEqual(a.license,"MIT");assert.ok(a.project.startsWith("https://"));assert.ok(a.issues.startsWith("https://"))});QUnit.test("possibleViews contains all five views",function(assert){const views=$.bsCalendar.possibleViews;assert.ok(Array.isArray(views));["day","4day","week","month","year"].forEach(v=>assert.ok(views.includes(v),`possibleViews includes "${v}"`))});QUnit.module("setDefaults / getDefaults",function(hooks){let originalLocale;hooks.beforeEach(function(){originalLocale=$.bsCalendar.getDefaults().locale});hooks.afterEach(function(){$.bsCalendar.setDefaults({locale:originalLocale})});QUnit.test("getDefaults returns the DEFAULTS object",function(assert){const d=$.bsCalendar.getDefaults();assert.strictEqual(typeof d,"object");assert.strictEqual(d.locale,"en-GB");assert.strictEqual(d.startView,"month")});QUnit.test("setDefaults mutates DEFAULTS",function(assert){$.bsCalendar.setDefaults({locale:"de-DE"});assert.strictEqual($.bsCalendar.getDefaults().locale,"de-DE")});QUnit.test("setDefaults deep-merges nested objects",function(assert){const originalEnd=$.bsCalendar.getDefaults().hourSlots.end;$.bsCalendar.setDefaults({hourSlots:{start:8}});const d=$.bsCalendar.getDefaults();assert.strictEqual(d.hourSlots.start,8,"start changed");assert.strictEqual(d.hourSlots.end,originalEnd,"end unchanged");$.bsCalendar.setDefaults({hourSlots:{start:0}})})});QUnit.module("Translations",function(){QUnit.test('getTranslations returns English for "en"',function(assert){const t=$.bsCalendar.getTranslations("en");assert.strictEqual(t.today,"Today");assert.strictEqual(t.month,"Month")});QUnit.test('getTranslations returns German for "de"',function(assert){const t=$.bsCalendar.getTranslations("de");assert.strictEqual(t.today,"Heute")});QUnit.test('getTranslations strips region tag — "de-DE" uses "de"',function(assert){const byCode=$.bsCalendar.getTranslations("de");const byLocale=$.bsCalendar.getTranslations("de-DE");assert.deepEqual(byCode,byLocale)});QUnit.test("getTranslations falls back to English for unknown locale",function(assert){const t=$.bsCalendar.getTranslations("xx");assert.strictEqual(t.today,"Today")});QUnit.test("getTranslation returns single key",function(assert){assert.strictEqual($.bsCalendar.getTranslation("de","today"),"Heute");assert.strictEqual($.bsCalendar.getTranslation("en","today"),"Today")});QUnit.test("getTranslation falls back to English for unknown locale",function(assert){assert.strictEqual($.bsCalendar.getTranslation("xx","today"),"Today")});QUnit.test("getTranslation returns key itself when key does not exist",function(assert){assert.strictEqual($.bsCalendar.getTranslation("en","__nonexistent__"),"__nonexistent__")});QUnit.test("addTranslation registers a new locale",function(assert){$.bsCalendar.addTranslation("eo",{today:"Hodiaŭ",day:"Tago","4day":"4 Tagoj",week:"Semajno",month:"Monato",year:"Jaro",search:"Tajpu kaj premu Enter",searchNoResult:"Neniu rendevuo trovita",tasks:"Taskoj",taskPriorityHigh:"Alta",taskPriorityNormal:"Normala",taskPriorityLow:"Malalta",duplicate:"Duobligi"});assert.strictEqual($.bsCalendar.getTranslation("eo","today"),"Hodiaŭ")});QUnit.test("addTranslation merges with English for missing keys",function(assert){$.bsCalendar.addTranslation("eo-custom",{today:"Hodiaŭ"});assert.strictEqual($.bsCalendar.getTranslation("eo-custom","month"),"Month")})})});